     1→export default {
     2→  async fetch(request, env, ctx) {
     3→    const url = new URL(request.url);
     4→
     5→    // Health check
     6→    if (url.pathname === '/health') {
     7→      return Response.json({ status: 'ok', timestamp: new Date().toISOString() });
     8→    }
     9→
    10→    // Get tenant config from KV
    11→    if (url.pathname === '/api/tenant-config' && request.method === 'GET') {
    12→      const tenantKey = url.searchParams.get('tenant');
    13→      if (!tenantKey) {
    14→        return Response.json({ error: 'Missing tenant parameter' }, { status: 400 });
    15→      }
    16→      const config = await env.TENANT_CONFIG.get(tenantKey, { type: 'json' });
    17→      if (!config) {
    18→        return Response.json({ error: 'Tenant not found' }, { status: 404 });
    19→      }
    20→      return Response.json(config);
    21→    }
    22→
    23→    // Get products with KV cache
    24→    if (url.pathname === '/api/products' && request.method === 'GET') {
    25→      const tenantId = url.searchParams.get('tenant_id');
    26→      const cacheKey = `products:tenant:${tenantId}`;
    27→
    28→      // Try KV cache first
    29→      const cached = await env.PRODUCT_CACHE.get(cacheKey, { type: 'json' });
    30→      if (cached) {
    31→        return Response.json({ ...cached, fromCache: true });
    32→      }
    33→
    34→      // Query D1
    35→      const results = await env.FRESHCART_DB
    36→        .prepare('SELECT p.*, c.name as category_name FROM products p JOIN categories c ON p.category_id = c.id WHERE p.tenant_id = ? AND p.is_active = 1')
    37→        .bind(tenantId)
    38→        .all();
    39→
    40→      // Cache in KV with 60s TTL
    41→      await env.PRODUCT_CACHE.put(cacheKey, JSON.stringify({ products: results.results }), { expirationTtl: 60 });
    42→
    43→      return Response.json({ products: results.results, fromCache: false });
    44→    }
    45→
    46→    return Response.json({ error: 'Not found' }, { status: 404 });
    47→  },
    48→};
